import type React from "react";

import { cva, type VariantProps } from "class-variance-authority";

import {
  EmptyState,
  EmptyStateDescription,
  EmptyStateTitle,
} from "../empty-state/EmptyState";
import { Skeleton } from "../skeleton/Skeleton";
import { cn } from "../utils/cn";

const cardListVariants = cva("grid gap-4", {
  variants: {
    columns: {
      1: "grid-cols-1",
      2: "grid-cols-1 sm:grid-cols-2",
      3: "grid-cols-1 sm:grid-cols-2 lg:grid-cols-3",
      4: "grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4",
    },
  },
  defaultVariants: {
    columns: 3,
  },
});

interface CardListOwnProps {
  /** Number of responsive grid columns. */
  columns?: 1 | 2 | 3 | 4;
  /** Show loading skeleton placeholders. */
  isLoading?: boolean;
  /** Number of skeleton cards to show when loading. */
  loadingCount?: number;
  /** Show the empty state instead of children. */
  isEmpty?: boolean;
  /** Title for the empty state. */
  emptyMessage?: string;
  /** Description for the empty state. */
  emptyDescription?: string;
}

type CardListProps = Omit<React.ComponentProps<"div">, "columns"> &
  CardListOwnProps;

/**
 * A responsive grid layout for cards with built-in loading and empty states.
 *
 * Renders children in a CSS grid. When `isLoading` is true, displays
 * skeleton placeholders. When `isEmpty` is true, displays an EmptyState.
 */
function CardList({
  className,
  children,
  columns = 3,
  isLoading = false,
  loadingCount = 6,
  isEmpty = false,
  emptyMessage = "No items found",
  emptyDescription,
  ...props
}: CardListProps) {
  if (isEmpty && !isLoading) {
    return (
      <div data-slot="card-list" className={cn(className)} {...props}>
        <EmptyState>
          <EmptyStateTitle>{emptyMessage}</EmptyStateTitle>
          {emptyDescription && (
            <EmptyStateDescription>{emptyDescription}</EmptyStateDescription>
          )}
        </EmptyState>
      </div>
    );
  }

  return (
    <div
      data-slot="card-list"
      className={cn(cardListVariants({ columns }), className)}
      {...props}
    >
      {isLoading
        ? Array.from({ length: loadingCount }, (_, i) => (
            <Skeleton
              key={i}
              data-slot="card-list-skeleton"
              className="h-36 rounded-lg"
            />
          ))
        : children}
    </div>
  );
}

export { CardList, cardListVariants };
export type { CardListProps };
